    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode =>
        AssignedRenderMode is null ? new InteractiveServerRenderMode() : null;

    // When the page declares [RenderModeAttribute(typeof(NoInteractiveRenderMode))],
