            {
                return null; // signals static SSR
            }
            // Default: interactive server
            return new InteractiveServerRenderMode();
        }
    }

    private IComponentRenderMode? PageRenderMode =>
        IsStaticPage ? null : new InteractiveServerRenderMode();

    private bool IsStaticPage
    {
        get
        {
            var endpoint = HttpContext?.GetEndpoint();
            return endpoint?.Metadata.GetMetadata<StaticRenderAttribute>() is not null;
        }
    }
}
"}

